pragma solidity ^0.8.20;

contract ClosedPresaleMint {
    enum State { CLOSED, PRESALE, PUBLIC }
    State public currentState = State.CLOSED;

    address private _owner;
    uint256 private _price;
    uint256 private _totalSupply;
    uint256 private _maxSupply;
    mapping(address => bool) private _claimedWhitelistStatus;

    event PresaleStarted();
    event PublicSaleStarted();
    event NFTMinted(address indexed buyer, uint256 indexed tokenId);
    event PublicNFTMinted(address indexed buyer, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == _owner, "Ownable: caller is not the owner");
        _;
    }

    constructor(uint256 price_, uint256 maxSupply_) {
        _owner = msg.sender;
        _price = price_;
        _maxSupply = maxSupply_;
    }

    function price() public view returns (uint256) {
        return _price;
    }

    function totalSupply() public view returns (uint256) {
        return _totalSupply;
    }

    function maxSupply() public view returns (uint256) {
        return _maxSupply;
    }

    function claimedWhitelistStatus(address account) public view returns (bool) {
        return _claimedWhitelistStatus[account];
    }

    function startPresale() public onlyOwner {
        require(currentState == State.CLOSED, "Presale cannot be started yet");
        currentState = State.PRESALE;
        emit PresaleStarted();
    }

