        require(currentState == State.PRESALE, "Public sale cannot be started yet");
        currentState = State.PUBLIC;
        emit PublicSaleStarted();
    }

    function mintNFT() external payable {
        require(currentState == State.PRESALE, "Presale is not active");
        require(!_claimedWhitelistStatus[msg.sender], "Address already claimed");
        require(msg.value == _price, "Incorrect payment amount");
        require(_totalSupply + 1 <= _maxSupply, "Exceeds maximum supply");

        _claimedWhitelistStatus[msg.sender] = true;
        _totalSupply += 1;

        emit NFTMinted(msg.sender, _totalSupply);
    }

    function mintPublicNFT(uint256 amount) external payable {
        require(currentState == State.PUBLIC, "Public sale is not active");
        require(amount > 0, "Amount must be greater than zero");
        require(msg.value == amount * _price, "Incorrect payment amount");
        require(_totalSupply + amount <= _maxSupply, "Exceeds maximum supply");

        _totalSupply += amount;

        emit PublicNFTMinted(msg.sender, amount);
    }
}
